"""
  BDEF: Unmanaged scenario declaration
"""
unmanaged implementation in class zbp_rap_unmanaged unique;
strict;
strict(2);
with draft;

define behavior for Z_ComplexBO alias ComplexBO
{
  create;
  update;
  delete;

  association _Child { create; with draft; }

  numbering managed;
  field ( numbering : managed ) BoID;

  determination setInitialStatus on modify { create; }
  validation validateBusinessRule on save { create; update; }

  action processResult result [1] $self;

  draft action Resume;
  draft action Edit;
  draft action Activate;
  draft action Discard;
}

"""
  Note the key difference from managed:
  - 'unmanaged implementation' instead of 'managed implementation'
  - No 'persistent table' (framework does not manage persistence)
  - No 'mapping' section (no direct table mapping)
  - All create/update/delete must be implemented manually
  - Draft action handlers must be implemented manually
"""

